import React, { useState } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [email, setEmail] = useState('');
  const [project, setProject] = useState(null);
  const [error, setError] = useState('');

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setProject(null);
    try {
      const res = await axios.get(`http://localhost:5000/api/track/${email}`);
      setProject(res.data);
    } catch (err) {
      setError("❌ No active project found for this email address.");
    }
  };

  return (
    <div className="container py-5 mt-4">
      {!project ? (
        /* १. क्लायंट लॉगिन विभाग */
        <div className="row justify-content-center">
          <div className="col-md-5 text-center">
            <div className="card shadow-lg border-0 p-4 rounded-4">
              <h3 className="fw-bold mb-3 text-primary">Client Login</h3>
              <p className="text-muted mb-4">Enter your registered email to access your dashboard.</p>
              <form onSubmit={handleLogin}>
                <input 
                  type="email" 
                  className="form-control mb-3 py-2 text-center" 
                  placeholder="name@example.com" 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  required 
                />
                <button className="btn btn-primary w-100 fw-bold py-2 shadow">View My Dashboard</button>
              </form>
              {error && <div className="text-danger mt-3 small">{error}</div>}
            </div>
          </div>
        </div>
      ) : (
        /* २. प्रत्यक्ष क्लायंट डॅशबोर्ड */
        <div className="row justify-content-center animate__animated animate__fadeIn">
          <div className="col-lg-8">
            <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
              <div className="bg-primary p-4 text-white d-flex justify-content-between align-items-center">
                <h4 className="mb-0 fw-bold">Welcome, {project.fullName}!</h4>
                <button className="btn btn-sm btn-outline-light" onClick={() => setProject(null)}>Logout</button>
              </div>
              
              <div className="card-body p-4 p-lg-5">
                <div className="row g-4 mb-4">
                  <div className="col-md-6">
                    <div className="p-3 border rounded-3 bg-light">
                      <small className="text-muted d-block">Project Type</small>
                      <h5 className="fw-bold">{project.serviceType}</h5>
                    </div>
                  </div>
                  <div className="col-md-6">
                    <div className="p-3 border rounded-3 bg-light">
                      <small className="text-muted d-block">Payment Status</small>
                      <h5 className={`fw-bold ${project.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}`}>
                        {project.paymentStatus}
                      </h5>
                    </div>
                  </div>
                </div>

                <div className="mb-5">
                  <div className="d-flex justify-content-between mb-2">
                    <h6 className="fw-bold">Project Work Progress</h6>
                    <span className="fw-bold text-primary">{project.progress}%</span>
                  </div>
                  <div className="progress rounded-pill shadow-sm" style={{ height: '25px' }}>
                    <div 
                      className={`progress-bar progress-bar-striped progress-bar-animated ${project.progress === 100 ? 'bg-success' : 'bg-primary'}`} 
                      style={{ width: `${project.progress}%` }}
                    ></div>
                  </div>
                  <p className="mt-3 text-muted">Current Work Status: <strong>{project.status}</strong></p>
                </div>

                <div className="alert alert-info border-0 rounded-3 small">
                  <i className="fas fa-info-circle me-2"></i>
                  This dashboard provides live updates on your project. If you have any questions, please contact the freelancer.
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default ClientDashboard;
